import React, { useState, useEffect, useRef } from 'react';
import { Typography } from '@mui/material';
import * as d3 from 'd3';
import axios from 'axios';

function AliToHussain({ user }) {
  const svgRef = useRef(null);
  const [chain, setChain] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const res = await axios.get('/api/ali-sherazia');
        // Filter to keep only Ali, Hasan, Hussain
        const filtered = res.data.filter(node => 
          node.name.includes('Ali ibn Abi Talib') ||
          node.name.includes('Hasan') ||
          node.name.includes('Hussain')
        );
        setChain(filtered);
      } catch (err) {
        console.error(err);
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, []);

  useEffect(() => {
    if (chain.length === 0) return;

    const svg = d3.select(svgRef.current);
    svg.selectAll('*').remove();

    // ─── DATA ───
    const ali = chain.find(n => n.name.includes('Ali ibn Abi Talib'));
    const hasan = chain.find(n => n.name.includes('Hasan'));
    const hussain = chain.find(n => n.name.includes('Hussain'));

    if (!ali) return;

    // ─── LAYOUT ───
    const boxW = 280, boxH = 200;
    const gapY = 80;
    const pad = 60;

    const aliX = 200, aliY = 100;
    const hasanX = aliX - boxW - 40, hussainX = aliX + boxW + 40;
    const childY = aliY + boxH + gapY;

    const totalWidth = 2 * boxW + 40 + 2 * pad;
    const totalHeight = childY + boxH + pad;

    svg.attr('width', totalWidth).attr('height', totalHeight)
      .attr('viewBox', `0 0 ${totalWidth} ${totalHeight}`);

    const mainGroup = svg.append('g');

    // ─── CONNECTORS ───
    const lineColor = '#2E7D32';
    const lineWidth = 2.5;

    // Ali → Hasan
    mainGroup.append('path')
      .attr('fill', 'none')
      .attr('stroke', lineColor)
      .attr('stroke-width', lineWidth)
      .attr('d', `M${aliX + boxW/2},${aliY + boxH} L${hasanX + boxW/2},${childY}`);

    // Ali → Hussain
    mainGroup.append('path')
      .attr('fill', 'none')
      .attr('stroke', lineColor)
      .attr('stroke-width', lineWidth)
      .attr('d', `M${aliX + boxW/2},${aliY + boxH} L${hussainX + boxW/2},${childY}`);

    // ─── DRAW NODES ───
    const drawNode = (x, y, node) => {
      const g = mainGroup.append('g').attr('transform', `translate(${x}, ${y})`);

      g.append('rect')
        .attr('width', boxW).attr('height', boxH)
        .attr('rx', 12).attr('ry', 12)
        .attr('fill', '#ffffffcc')
        .attr('stroke', '#2E7D32')
        .attr('stroke-width', 2.5);

      g.append('rect')
        .attr('width', boxW).attr('height', 6)
        .attr('rx', 3).attr('fill', '#2E7D32');

      const father = node.father_name || '';
      const fatherLine = father ? `bin ${father}` : '';
      const wifeLine = node.wife_name ? `💍 ${node.wife_name}` : '';

      g.append('foreignObject')
        .attr('width', boxW - 20).attr('height', boxH - 60)
        .attr('x', 10).attr('y', 10)
        .append('xhtml:div')
        .style('width', '100%').style('height', '100%')
        .style('display', 'flex').style('flex-direction', 'column')
        .style('align-items', 'center').style('justify-content', 'center')
        .style('text-align', 'center')
        .style('font-size', '14px')
        .style('line-height', '1.3')
        .html(`
          <b>${node.name}</b>
          ${father ? `<br/><span style="font-size:12px;color:#1565C0;">${fatherLine}</span>` : ''}
          ${wifeLine ? `<br/><span style="font-size:12px;color:#C2185B;">${wifeLine}</span>` : ''}
          <br/><span style="font-size:11px;color:#555;">Gen: ${node.generation_number}</span>
          ${node.info ? `<br/><span style="font-size:11px;color:#777;">${node.info}</span>` : ''}
        `);
    };

    if (ali) drawNode(aliX, aliY, ali);
    if (hasan) drawNode(hasanX, childY, hasan);
    if (hussain) drawNode(hussainX, childY, hussain);

  }, [chain]);

  if (loading) return <Typography sx={{ textAlign: 'center', mt: 4 }}>Loading...</Typography>;

  return (
    <div style={{ width: '100%', height: '100%', display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
      <Typography variant="h5" align="center" sx={{ mt: 2, mb: 1, color: '#2E7D32', fontWeight: 'bold' }}>
        سلسلہ: حضرت علی (ع) تا حضرت حسین (ع)
      </Typography>
      <div style={{ flex: 1, padding: '10px', overflow: 'auto' }}>
        <svg ref={svgRef} style={{ display: 'block', width: '100%', minHeight: '100%' }} />
      </div>
    </div>
  );
}

export default AliToHussain;
